// NavBar.tsx
import React, { useState } from "react";
import styles from "./nav-bar.module.css";
import NavButton from "../nav-button";
import MegaMenu from "../mega-menu";

const NavBar: React.FC = () => {
  const [isMegaMenuVisible, setIsMegaMenuVisible] = useState<boolean>(false);

  // Function to toggle MegaMenu visibility
  const toggleMegaMenu = () => {
    setIsMegaMenuVisible(!isMegaMenuVisible);
  };

  return (
    <>
      <div className={styles.nav__bar}>
        <NavButton text="Discovery" handleClick={toggleMegaMenu} />
        <NavButton text="About" handleClick={toggleMegaMenu} />
        <NavButton text="Contact us" href="/contact" isLink={true} />
      </div>
      <MegaMenu show={isMegaMenuVisible} />
    </>
  );
};

export default NavBar;

